// Aggregate planning outputs from all LLMs
const plotData = $('ChatGPT: Plot Outline').item.json;
const characterData = $('Claude: Character Development').item.json;
const researchData = $('Perplexity: Research & Facts').item.json;
const projectState = $('Initialize Project State').item.json;

// Parse responses
let plotOutline = {};
let characters = {};
let research = {};

try {
  if (plotData.choices && plotData.choices[0]) {
    const content = plotData.choices[0].message.content;
    // Try to extract JSON from response
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    plotOutline = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: content };
  }
} catch (e) {
  plotOutline = { raw: plotData.choices?.[0]?.message?.content || 'Parse error' };
}

try {
  if (characterData.content && characterData.content[0]) {
    const content = characterData.content[0].text;
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    characters = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: content };
  }
} catch (e) {
  characters = { raw: characterData.content?.[0]?.text || 'Parse error' };
}

try {
  if (researchData.choices && researchData.choices[0]) {
    research = { content: researchData.choices[0].message.content };
  }
} catch (e) {
  research = { raw: 'Research parse error' };
}

return {
  json: {
    ...projectState,
    status: 'planning_complete',
    planning: {
      plotOutline,
      characters,
      research,
      completedAt: new Date().toISOString()
    }
  }
};

