// Update chapter with revision
const projectState = $('Aggregate Review Feedback').item.json;
const revision = $('Claude: Apply Revisions').item.json;

let revisedText = '';
if (revision.content && revision.content[0]) {
  revisedText = revision.content[0].text;
}

// Track revision iteration
const revisionCount = (projectState.currentChapterDraft.revisionCount || 0) + 1;

return {
  json: {
    ...projectState,
    currentChapterDraft: {
      ...projectState.currentChapterDraft,
      text: revisedText,
      wordCount: revisedText.split(/\s+/).length,
      revisionCount: revisionCount,
      lastRevisedAt: new Date().toISOString()
    },
    review: {
      ...projectState.review,
      needsRevision: revisionCount < 3  // Max 3 revision cycles
    }
  }
};

// Finalize the current chapter
const projectState = $('Aggregate Review Feedback').item.json;

// Store completed chapter
const chapters = projectState.completedChapters || [];
chapters.push({
  number: parseInt(projectState.currentChapter),
  text: projectState.currentChapterDraft.text,
  wordCount: projectState.currentChapterDraft.wordCount,
  finalScore: projectState.review.averageScore,
  completedAt: new Date().toISOString()
});

const currentChapter = parseInt(projectState.currentChapter);
const targetChapters = parseInt(projectState.targetChapters);

return {
  json: {
    ...projectState,
    completedChapters: chapters,
    currentChapter: (currentChapter + 1).toString(),
    status: currentChapter >= targetChapters ? 'complete' : 'drafting'
  }
};

// Compile all chapters into final manuscript
const projectState = $('Finalize Chapter').item.json;

const chapters = projectState.completedChapters || [];

// Build manuscript
let manuscript = `# ${projectState.concept.substring(0, 100)}\n`;
manuscript += `## A ${projectState.genre} Novel\n\n`;
manuscript += `---\n\n`;

for (const chapter of chapters.sort((a, b) => a.number - b.number)) {
  manuscript += `# Chapter ${chapter.number}\n\n`;
  manuscript += chapter.text;
  manuscript += `\n\n---\n\n`;
}

const totalWords = chapters.reduce((sum, ch) => sum + ch.wordCount, 0);
const avgScore = chapters.reduce((sum, ch) => sum + parseFloat(ch.finalScore), 0) / chapters.length;

return {
  json: {
    ...projectState,
    manuscript: manuscript,
    summary: {
      totalChapters: chapters.length,
      totalWords: totalWords,
      averageScore: avgScore.toFixed(1),
      completedAt: new Date().toISOString()
    }
  }
};
